        // or it contains only dots or spaces.
        invalidUserNameCharsRegex      = regexp.MustCompile(`["/\\:;|=,\+\*\?<>@\[\]]`)
        invalidUserNameDotsSpacesRegex = regexp.MustCompile(`^[\. ]+$`)
)

